✓ CORRECT: Per-CPU Array
c
struct {
__uint(type, BPF_MAP_TYPE_PERCPU_ARRAY);
__uint(max_entries, 1);
__type(key, u32);
__type(value, struct event);
} heap SEC(".maps");
SEC("kprobe/do_sys_open")
int trace_open(struct pt_regs *ctx) {
u32 key = 0;
struct event *e =
bpf_map_lookup_elem(&heap, &key);
if (!e) return 0;
// Use e->filename[256] safely
}

Per-CPU Array
c
// One copy per CPU
// No synchronization needed
BPF_MAP_TYPE_PERCPU_ARRAY

Hash Map
c
// Keyed by thread ID
// Shared across CPUs
BPF_MAP_TYPE_HASH

Ring Buffer
c
// Reserve, fill, submit
// Zero-copy to userspace
BPF_MAP_TYPE_RINGBUF
